  ensures forall k :: k in paths ==> k in result
{
  result := map[];

  var keys := paths.Keys;

  while keys != {}
    decreases |keys|
  {
    var key :| key in keys;
    keys := keys - {key};

    var path := paths[key];
    var value := resolve_path(record, path, default_val);
    result := result[key := value];
  }
}

method resolve_path(record: map<string, object?>, path: string, default_val: object?) returns (result: object?)
{
  var parts := split_dots(path);

  if |parts| == 0 {
    result := default_val;
    return;
  }

  var current: object? := record;
  var i := 0;

  while i < |parts|
    decreases |parts| - i
  {
    var part := parts[i];

    if current == null {
      result := default_val;
      return;
    }

    if current is map<string, object?> {
      var m := current as map<string, object?>;
      if part in m {
        current := m[part];
      } else {
        result := default_val;
        return;
      }
    } else if current is seq<object?> {
      var s := current as seq<object?>;
      var idx := parse_int(part);
      if idx >= 0 && idx < |s| {
        current := s[idx];
      } else {
        result := default_val;
        return;
      }
    } else {
      result := default_val;
      return;
    }

    i := i + 1;
  }

  result := current;
}

